import React, { useState } from 'react';
import logoAgro from '../../assets/logoAgro.png';
import {useNavigate} from 'react-router-dom';
import'./Login.css';

const Login = () => {
const [email, setEmail] = useState('');
const [password, setPassword] = useState('');
const [verificationCode, setVerificationCode] = useState('');

const handleSubmit = (e) => {
    e.preventDefault();
    console.log("Dados enviados: ", { email, password });
    // TODO: Implementar lógica de autenticação 
}

const Login = () => {
    const navagate = useNavigate();
    const handleSubmit = (e) => {
        e.preventDefault();
        //Fazer a chamada para o backend para autenticar o usuário
        //Se a autenticação for bem-sucedida, redirecionar para o dashboard
        navagate('/dashboard');
    }
}

    return(
        <div className="Login-container">
            <div className="login-form">
                <h2>Login</h2>
                <form onSubmit={handleSubmit}>
                    <div className="input-group">
                        <label htmlFor="email">E-mail</label>
                        <div className="input-with-icon"></div>
                        <input type="email" id="email" placeholder="exemplo@gmail.com" value={email} onChange={(e) => setEmail(e.target.value)} required />
                    </div>
                    <div className="input-group">
                        <label htmlFor="password">Senha</label>
                        <input type="password" id="password" placeholder="Digite sua senha" value={password} onChange={(e) => setPassword(e.target.value)} required />
                    </div>
                    <div className="input-group">
                        <label htmlFor="verificationCode">Código de Verificação</label>
                        <input type="text" id="verificationCode" placeholder="Digite o código de verificação" maxLength={"6"} required />
                    </div>
                    <a href="forgot-password-link" className="forgot-password-link">Esqueci minha senha</a>
                    <button type="submit" className="button">Entrar</button>
                </form>
                <div className="login-forget">
                    <p>Não tem uma conta? <a href="register-link" className="forgot-password-links">Cadastre-se</a></p>
                </div>
            </div>
            <div className="login-image">
                <img src={logoAgro} alt="Logo do Agromonitor"/>
            </div>
        </div>
    );
};

export default Login;
